CREATE OR REPLACE FUNCTION public.admin_take_moderation_case(p_flag_id uuid)
 RETURNS TABLE(ok boolean, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_actor_id uuid;
BEGIN
  v_actor_id := auth.uid();
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF NOT public.has_admin_role('admin_ops') THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  IF p_flag_id IS NULL THEN
    RAISE EXCEPTION 'p_flag_id is required';
  END IF;

  PERFORM public.admin_update_moderation_flag(
    p_flag_id,
    'in_review',
    NULL,
    jsonb_build_object('action', 'take_case')
  );

  RETURN QUERY SELECT true, 'case_taken'::text;
END;
$function$

CREATE OR REPLACE FUNCTION public.has_any_exact_admin_role(required_roles text[])
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  current_user_id uuid;
BEGIN
  current_user_id := auth.uid();
  IF current_user_id IS NULL THEN
    RETURN false;
  END IF;

  IF required_roles IS NULL OR cardinality(required_roles) = 0 THEN
    RETURN false;
  END IF;

  RETURN EXISTS (
    SELECT 1
    FROM public.admin_role_members arm
    WHERE arm.user_id = current_user_id
      AND arm.role_key = ANY(required_roles)
  );
END;
$function$

