CREATE OR REPLACE FUNCTION public.admin_add_user_note(p_target_user_id uuid, p_note text)
 RETURNS TABLE(id uuid, target_user_id uuid, actor_user_id uuid, note text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_actor_id uuid;
  v_note text;
  v_inserted public.admin_user_notes%ROWTYPE;
BEGIN
  v_actor_id := auth.uid();
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF NOT public.is_admin_any_role(v_actor_id, ARRAY['admin_support', 'admin_ops', 'admin_super']::text[]) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  IF p_target_user_id IS NULL THEN
    RAISE EXCEPTION 'p_target_user_id is required';
  END IF;

  v_note := NULLIF(trim(COALESCE(p_note, '')), '');
  IF v_note IS NULL THEN
    RAISE EXCEPTION 'p_note is required';
  END IF;

  INSERT INTO public.admin_user_notes (
    target_user_id,
    actor_user_id,
    note
  ) VALUES (
    p_target_user_id,
    v_actor_id,
    v_note
  )
  RETURNING * INTO v_inserted;

  PERFORM public.log_admin_action(
    p_action => 'user_internal_note_added',
    p_target_type => 'user',
    p_target_id => p_target_user_id::text,
    p_meta => jsonb_build_object(
      'note', v_note,
      'admin_user_note_id', v_inserted.id
    ),
    p_actor_user_id => v_actor_id
  );

  RETURN QUERY
  SELECT
    v_inserted.id,
    v_inserted.target_user_id,
    v_inserted.actor_user_id,
    v_inserted.note,
    v_inserted.created_at;
END;
$function$

