CREATE OR REPLACE FUNCTION public.create_impersonation_session(target_user_id uuid, minutes integer DEFAULT 30, reason text DEFAULT NULL::text, meta jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  actor_id uuid;
  inserted_id uuid;
  ttl_minutes integer;
  resolved_target_role text;
BEGIN
  actor_id := auth.uid();
  IF actor_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF NOT public.has_any_exact_admin_role(ARRAY['admin_support', 'admin_super']) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  IF target_user_id IS NULL THEN
    RAISE EXCEPTION 'target_user_id is required';
  END IF;

  IF actor_id = target_user_id THEN
    RAISE EXCEPTION 'Cannot impersonate self';
  END IF;

  SELECT CASE WHEN u.role = 'business' THEN 'business' ELSE 'customer' END
  INTO resolved_target_role
  FROM public.users u
  WHERE u.id = target_user_id;

  IF resolved_target_role IS NULL THEN
    RAISE EXCEPTION 'Target user not found';
  END IF;

  ttl_minutes := GREATEST(COALESCE(minutes, 30), 1);

  INSERT INTO public.admin_impersonation_sessions (
    actor_user_id,
    target_user_id,
    target_role,
    reason,
    meta,
    expires_at,
    active
  ) VALUES (
    actor_id,
    target_user_id,
    resolved_target_role,
    reason,
    COALESCE(meta, '{}'::jsonb) || jsonb_build_object('target_role', resolved_target_role),
    now() + make_interval(mins => ttl_minutes),
    true
  )
  RETURNING id INTO inserted_id;

  PERFORM public.log_admin_action(
    p_action => 'impersonation_start',
    p_target_type => 'user',
    p_target_id => target_user_id::text,
    p_meta => jsonb_build_object(
      'session_id', inserted_id,
      'minutes', ttl_minutes,
      'reason', reason,
      'target_role', resolved_target_role,
      'meta', COALESCE(meta, '{}'::jsonb)
    ),
    p_actor_user_id => actor_id
  );

  RETURN inserted_id;
END;
$function$

