CREATE OR REPLACE FUNCTION public.sync_listing_category_fields()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  resolved_name text;
  resolved_id uuid;
  normalized_input text;
BEGIN
  -- Normalize the incoming category string (if present)
  IF NEW.category IS NOT NULL THEN
    normalized_input := lower(trim(NEW.category));
    IF normalized_input = '' THEN
      normalized_input := NULL;
    END IF;
  ELSE
    normalized_input := NULL;
  END IF;

  -- Prefer category_id as the source of truth
  IF NEW.category_id IS NOT NULL THEN
    SELECT bc.name INTO resolved_name
    FROM public.business_categories bc
    WHERE bc.id = NEW.category_id;

    IF resolved_name IS NOT NULL THEN
      -- Always set to canonical name (also normalizes whitespace/case drift)
      IF NEW.category IS DISTINCT FROM resolved_name THEN
        NEW.category := resolved_name;
      END IF;
    END IF;

  -- Otherwise, attempt to resolve category_id from the category string
  ELSIF normalized_input IS NOT NULL THEN
    SELECT bc.id, bc.name INTO resolved_id, resolved_name
    FROM public.business_categories bc
    WHERE lower(trim(bc.name)) = normalized_input
    LIMIT 1;

    IF resolved_id IS NOT NULL THEN
      NEW.category_id := resolved_id;
      -- Canonicalize stored name too
      NEW.category := resolved_name;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
